from flask import Flask, request, jsonify
import jwt
from functools import wraps

app = Flask(__name__)

# Configuration for different signing algorithms
ALGORITHMS = {
    'HS256': 'your_secret_key',
    'RS256': 'path_to_your_public_key'
}

def verify_jwt(algorithm):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token = request.headers.get('Authorization')
            if not token:
                return jsonify({'error': 'Missing JWT token'}), 401

            try:
                payload = jwt.decode(token.split()[1], ALGORITHMS[algorithm], algorithms=[algorithm])
                request.payload = payload
            except jwt.ExpiredSignatureError:
                return jsonify({'error': 'Token has expired'}), 401
            except jwt.InvalidTokenError:
                return jsonify({'error': 'Invalid token'}), 401

            return f(*args, **kwargs)
        return decorated_function
    return decorator

@app.route('/internal', methods=['GET'])
@verify_jwt('HS256')
def internal_route():
    user_id = request.payload['user_id']
    return jsonify({'message': f'Welcome, {user_id}! This is an internal route.'})

@app.route('/public', methods=['GET'])
@verify_jwt('RS256')
def public_route():
    token_info = request.payload
    return jsonify({'message': 'This is a public route.', 'token_info': token_info})

if __name__ == '__main__':
    app.run(debug=True)